import socket
import ssl

def check_endpoint(url, name, timeout=5):
    print(f"Checking {name} -> {url}")
    try:
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
        response = urllib.request.urlopen(req, timeout=timeout)
        status = response.getcode()
        body = response.read().decode('utf-8')
        print(f"{name}: SUCCESS - HTTP {status}, Body: '{body.strip()[:200]}...'")
    except urllib.error.HTTPError as e:
        print(f"{name}: HTTP Error - {e.code} {e.reason}")
    except urllib.error.URLError as e:
        if isinstance(e.reason, (socket.timeout, ssl.SSLError)):
            print(f"{name}: Timeout or SSL Error - {e.reason}")
        else:
